const BANDS = [
  { min: 0, max: 20, label: "Terrible", icon: FACE_TERRIBLE },
  { min: 20, max: 40, label: "Not great", icon: FACE_NOT_GREAT },
  { min: 40, max: 60, label: "Fine", icon: FACE_FINE },
  { min: 60, max: 80, label: "Pretty good", icon: FACE_PRETTY_GOOD },
  { min: 80, max: 101, label: "Fantastic", icon: FACE_FANTASTIC },
];

function bandFor(value: number) {
  return BANDS.find((b) => value >= b.min && value < b.max) ?? BANDS[4];
}

// Per Figma inset values for the .line group (343.879 × 52.679).
const LINE_TRANSLATES: ReadonlyArray<readonly [number, number]> = [
  [7.87, 13.06],
  [90.1, 0.06],
  [178.18, 0.06],
  [263.81, 13.06],
];
const LINE_WIDTHS = [72.18, 75.588, 75.588, 72.18];
const DOT_TRANSLATES: ReadonlyArray<readonly [number, number]> = [
  [0, 44.25],
  [80.92, 11.38],
  [167.71, 0],
  [254.5, 11.38],
  [335.46, 44.25],
];
const DOT_CENTERS: ReadonlyArray<readonly [number, number]> = DOT_TRANSLATES.map(
  ([tx, ty]) => [tx + 4.21, ty + 4.21] as const,
);

export function FeelingSlider({ value, onChange }: FeelingSliderProps) {
  const { state } = useApp();
  const metabolicType = toMetabolicType(state.user.metabolicType) ?? "Explorer";
  const ACTIVE = TC[metabolicType].bg;
  // RES-144: a native horizontal ScrollView drives the value instead of a
  // PanResponder drag. Nested orthogonal scrolling lets the parent vertical
  // survey ScrollView keep vertical pans while this owns horizontal ones, so the
  // gesture is reliable (the old pan drag was being stolen by the parent).
  const [trackWidth, setTrackWidth] = useState(0);
  const scrollRef = useRef<ScrollView>(null);
  const didInit = useRef(false);

  const handleLayout = (e: LayoutChangeEvent) => {
    setTrackWidth(e.nativeEvent.layout.width);
  };

  // Scroll offset maps to the 0–100 value, inverted so the knob tracks the
  // finger: a ScrollView's content moves opposite the finger, so swiping right
  // (offset decreases) must raise the value (knob moves right).
  const handleScroll = (e: NativeSyntheticEvent<NativeScrollEvent>) => {
    if (trackWidth <= 0) return;
    const x = e.nativeEvent.contentOffset.x;
    const pct = Math.max(0, Math.min(100, 100 - (x / trackWidth) * 100));
    onChange(Math.round(pct));
  };

  // Once the content is laid out, jump the scroll position to match `value`
  // (default 50 → centered) so the knob starts where it should. One-shot.
  const handleContentSizeChange = () => {
    if (didInit.current || trackWidth <= 0) return;
    didInit.current = true;
    scrollRef.current?.scrollTo({
      x: ((100 - value) / 100) * trackWidth,
      animated: false,
    });
  };

  const band = bandFor(value);

  // Knob position along the piecewise curve, computed by linear interpolation
  // between adjacent dot centers (5 anchors, 4 segments at 25%-wide bands).
  const segIdx = Math.min(3, Math.floor(value / 25));
  const segT = (value - segIdx * 25) / 25;
  const [x0, y0] = DOT_CENTERS[segIdx];
  const [x1, y1] = DOT_CENTERS[segIdx + 1];
  const knobX = x0 + (x1 - x0) * segT;
  const knobY = y0 + (y1 - y0) * segT;
  const knobLeftPct = (knobX / VIEWBOX_W) * 100;
  // The track has aspect 35/6 but the SVG viewBox has aspect ~6.53, so
  // `preserveAspectRatio="meet"` scales the SVG to fit the track's width
  // and adds vertical letterboxing. Compensate so the knob lands on the
  // actual rendered curve rather than against the full track height.
  const TRACK_ASPECT = 35 / 6;
  const SVG_ASPECT = VIEWBOX_W / VIEWBOX_H;
  const ySCALE = TRACK_ASPECT / SVG_ASPECT;
  const yOFFSET = (1 - ySCALE) / 2;
  const knobTopPct = (yOFFSET + (knobY / VIEWBOX_H) * ySCALE) * 100;
  // Rotation: each of the 4 segments has its own slope. To avoid a sharp
  // angle change at each dot, blend between adjacent segment slopes around
  // every dot — pure segment slope at segment midpoints (12.5/37.5/62.5/87.5),
  // averaged across the dots (25/50/75).
  const segmentSlopes = [0, 1, 2, 3].map((i) =>
    Math.atan2(
      DOT_CENTERS[i + 1][1] - DOT_CENTERS[i][1],
      DOT_CENTERS[i + 1][0] - DOT_CENTERS[i][0],
    ),
  );
  const smoothedSlope = (() => {
    if (value <= 12.5) return segmentSlopes[0];
    if (value >= 87.5) return segmentSlopes[3];
    const blendIdx = value < 37.5 ? 0 : value < 62.5 ? 1 : 2;
    const start = 12.5 + blendIdx * 25;
    const t = (value - start) / 25;
    return segmentSlopes[blendIdx] * (1 - t) + segmentSlopes[blendIdx + 1] * t;
  })();
  const handleRotation = (smoothedSlope * 180) / Math.PI;

  // For each line section, compute the knob's local progress (0..1) within
  // that section's x-range. Used to drive a hard-stop gradient so the section
  // fills proportionally as the knob crosses it.
  const lineProgress = LINE_TRANSLATES.map(([tx], i) => {
    const w = LINE_WIDTHS[i];
    return Math.max(0, Math.min(1, (knobX - tx) / w));
  });
  const dotActive = [0, 1, 2, 3, 4].map((i) => value >= i * 25);

  return (
    <View style={styles.container}>
      <View style={styles.decoration}>
        <View style={[styles.faceCircle, { backgroundColor: ACTIVE }]}>
          <Svg width={98.519} height={98.519} viewBox="0 0 99 99" fill="none">
            <Path d={band.icon} fill="#361416" />
          </Svg>
        </View>
        <Text style={styles.label}>{band.label}</Text>
      </View>

      <View style={styles.track} onLayout={handleLayout}>
        <Svg
          width="100%"
          height="100%"
          viewBox={`0 0 ${VIEWBOX_W} ${VIEWBOX_H}`}
          preserveAspectRatio="xMidYMid meet"
        >
          <Defs>
            {lineProgress.map((p, i) => (
              <LinearGradient
                key={`grad-${i}`}
                id={`line-grad-${i}`}
                x1="0"
                y1="0"
                x2="1"
                y2="0"
              >
                <Stop offset={p} stopColor={ACTIVE} />
                <Stop offset={p} stopColor={INACTIVE_LINE} />
              </LinearGradient>
            ))}
          </Defs>
          {LINE_TRANSLATES.map(([tx, ty], i) => (
            <G key={`line-${i}`} transform={`translate(${tx}, ${ty})`}>
              <Path
                d={[LINE_1, LINE_2, LINE_3, LINE_4][i]}
                fill={`url(#line-grad-${i})`}
              />
            </G>
          ))}
          {DOT_TRANSLATES.map(([tx, ty], i) => (
            <G key={`dot-${i}`} transform={`translate(${tx}, ${ty})`}>
              <Path
                d={[DOT_1, DOT_2, DOT_3, DOT_4, DOT_5][i]}
                fill={dotActive[i] ? ACTIVE : INACTIVE_LINE}
              />
            </G>
          ))}
        </Svg>
        <View
          pointerEvents="none"
          style={[
            styles.handle,
            {
              left: `${knobLeftPct}%`,
              top: `${knobTopPct}%`,
            },
          ]}
        >
          <View
            style={[
              styles.handleInner,
              { transform: [{ rotate: `${handleRotation}deg` }] },
            ]}
          >
            <View style={styles.handleBar} />
            <View style={styles.handleBar} />
            <View style={styles.handleBar} />
          </View>
        </View>
        {/* Transparent horizontal scroll overlay — owns the drag gesture and
            drives `value`. Snaps to the 5 dot positions (value 0/25/50/75/100,
            one per feeling band). The visuals above render from `value`. */}
        {trackWidth > 0 ? (
          <ScrollView
            ref={scrollRef}
            horizontal
            bounces={false}
            showsHorizontalScrollIndicator={false}
            style={StyleSheet.absoluteFill}
            contentContainerStyle={{ width: trackWidth * 2 }}
            snapToInterval={trackWidth / 4}
            snapToAlignment="start"
            disableIntervalMomentum
            decelerationRate="fast"
            scrollEventThrottle={16}
            onScroll={handleScroll}
            onContentSizeChange={handleContentSizeChange}
          >
            <View style={styles.scrollSpacer} />
          </ScrollView>
        ) : null}
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    width: "100%",
    gap: 24,
    alignItems: "center",
    paddingHorizontal: spacing.md,
  },
  decoration: {
    alignItems: "center",
    paddingVertical: 24,
    gap: 16,
  },
  faceCircle: {
    width: 108.889,
    height: 108.889,
    borderRadius: 108.889 / 2,
    alignItems: "center",
    justifyContent: "center",
  },
  label: {
    fontFamily: fonts.dmSans,
    fontSize: 32,
    lineHeight: 38,
    letterSpacing: -0.32,
    color: K.brown,
    textAlign: "center",
  },
  track: {
    width: "100%",
    aspectRatio: 35 / 6,
    position: "relative",
  },
  scrollSpacer: {
    height: "100%",
  },
  handle: {
    position: "absolute",
    width: HANDLE_SIZE,
    height: HANDLE_SIZE,
    marginLeft: -HANDLE_SIZE / 2,
    marginTop: -HANDLE_SIZE / 2,
    alignItems: "center",
    justifyContent: "center",
  },
  handleInner: {
    flexDirection: "row",
    alignItems: "center",
    gap: 4,
    paddingHorizontal: 16,
    paddingVertical: 8,
    borderRadius: 999,
    backgroundColor: K.brown,
    shadowColor: "#000",
    shadowOpacity: 0.25,
    shadowRadius: 4,
    shadowOffset: { width: 0, height: 4 },
    elevation: 4,
  },
  handleBar: {
    width: 2,
    height: 8,
    borderRadius: 1,
    backgroundColor: K.white,
  },
});
